import { Col, Form, Input, InputNumber, Row } from 'antd';
import PropTypes from 'prop-types';
import CustomModal from 'src/components/Modal/CustomModal';
import ButtonCustom from 'src/components/MyButton/Button';
import SelectCustom from 'src/components/Select/SelectCustom';
import TitleCustom from 'src/components/TitleCustom';
import FeeManagement from 'src/services/FeeManagement';
import InputCustom from 'src/components/Input/InputCustom';
import notice from 'src/components/Notice';
import { getListComboByKey } from "src/lib/utils"
import { SYSTEM_KEY } from "src/constants/constants"
import { useMemo } from 'react';
import { useSelector } from 'react-redux';
import '../styles/FeeModal.scss';
const { TextArea } = Input;

const FeeExternalModal = ({ visible, onCancel, onOk, onSuccess }) => {
    const [form] = Form.useForm();

    const { listSystemKey } = useSelector(state => state.appGlobal)

    const feeTypeList = useMemo(
        () => getListComboByKey(SYSTEM_KEY.FEE_TYPE, listSystemKey) || [],
        [listSystemKey],
    )
    // Hàm format hiển thị
    const formatCurrency = value => {
        if (!value) return '';
        return value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');
    };

    // Hàm parse ngược về số
    const parseCurrency = value => {
        if (!value) return '';
        return value.toString().replace(/,/g, '');
    };

    const handleOk = async () => {
        try {
            const values = await form.validateFields();
            const body = { ...values };

            const response = await FeeManagement.postFeeExternal(body);

            if (response?.isOk) {
                notice({ msg: "Khoản phí đã được tạo thành công." });
                onOk?.(response.data);
                onSuccess?.();
                form.resetFields();
            } else {
                notice({ msg: "Tạo khoản phí thất bại!", isSuccess: false });
            }
        } catch (error) {
            const errorMessage =
                error?.response?.data?.message || "Đã xảy ra lỗi khi tạo khoản phí!";
            console.error("Submission failed:", error);
            notice({ msg: errorMessage, isSuccess: false });
        }
    };

    const handleCancel = () => {
        form.resetFields();
        onCancel();
    };

    return (
        <CustomModal
            visible={visible}
            onCancel={handleCancel}
            footer={null}
            width={700}
            className="fee-modal"
        >
            <div className="form-container">
                <TitleCustom level={3} className="mb-4">Tạo Khoản Thu/Chi Bên Ngoài</TitleCustom>

                <Form form={form} layout="vertical" className="fee-form">
                    <Form.Item
                        label="Mô Tả"
                        name="Note"
                        className='mt-6'
                        rules={[
                            { required: true, message: 'Vui lòng nhập mô tả!' },
                            { max: 200, message: 'Mô tả không được vượt quá 200 ký tự!' },
                        ]}
                    >
                        <TextArea rows={4} placeholder="Nhập mô tả giao dịch" className="rounded-md" />
                    </Form.Item>

                    <Row gutter={16}>
                        <Col span={12}>
                            <Form.Item label="Phạm Vi Giao Dịch">
                                <Input value="Bên Ngoài" disabled className="rounded-md" />
                            </Form.Item>
                        </Col>
                        <Col span={12}>
                            <Form.Item
                                label="Nguồn/Đích"
                                name="EntityName"
                                rules={[
                                    { required: true, message: 'Vui lòng nhập nguồn/đích!' },
                                    { max: 100, message: 'Không vượt quá 100 ký tự!' },
                                ]}
                            >
                                <InputCustom placeholder="Nhập tên tổ chức/cá nhân" className="rounded-md" />
                            </Form.Item>
                        </Col>
                    </Row>

                    <Row gutter={16}>
                        <Col span={12}>
                            <Form.Item
                                label="Loại Giao Dịch"
                                name="FeeType"
                                rules={[{ required: true, message: 'Vui lòng chọn loại giao dịch!' }]}
                            >
                                <SelectCustom placeholder="Chọn loại giao dịch" className="w-full">
                                    {feeTypeList.map((item) => (
                                        <SelectCustom.Option key={item.CodeKey} value={item.CodeValue}>
                                            {item.Description}
                                        </SelectCustom.Option>
                                    ))}
                                </SelectCustom>
                            </Form.Item>
                        </Col>
                        <Col span={12}>
                            <Form.Item
                                label="Số Tiền"
                                name="Amount"
                                rules={[
                                    { required: true, message: 'Vui lòng nhập số tiền!' },
                                    {
                                        validator: (_, value) => {
                                            const parsedValue = parseCurrency(value);
                                            const num = Number(parsedValue);
                                            if (!parsedValue || isNaN(num) || num <= 0) {
                                                return Promise.reject(new Error('Số tiền phải là số dương!'));
                                            }
                                            if (num > 2000000000) {
                                                return Promise.reject(new Error('Số tiền không được vượt quá 2 tỷ!'));
                                            }
                                            return Promise.resolve();
                                        },
                                    },
                                ]}
                            >
                                <InputNumber
                                    className="w-full rounded-md"
                                    placeholder="VD: 1,000,000"
                                    formatter={formatCurrency}
                                    parser={parseCurrency}
                                    suffix=" VND"
                                    max={2000000000}
                                    min={0}
                                    style={{ width: '100%' }}
                                />
                            </Form.Item>
                        </Col>
                    </Row>

                    <Row gutter={16} justify="end" className="mt-6">
                        <Col>
                            <ButtonCustom className="w-[120px] rounded-md" onClick={handleCancel}>
                                Quay Lại
                            </ButtonCustom>
                        </Col>
                        <Col>
                            <ButtonCustom className="w-[120px] rounded-md" onClick={handleOk}>
                                Tạo
                            </ButtonCustom>
                        </Col>
                    </Row>
                </Form>
            </div>
        </CustomModal>
    );
};

FeeExternalModal.propTypes = {
    visible: PropTypes.bool.isRequired,
    onCancel: PropTypes.func.isRequired,
    onOk: PropTypes.func.isRequired,
    onSuccess: PropTypes.func.isRequired,
};

export default FeeExternalModal;
