import { Col, DatePicker, InputNumber, Row } from "antd"
import dayjs from "dayjs"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import SvgIcon from "src/components/SvgIcon"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import TitleCustom from "src/components/TitleCustom"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import FeeManagement from "src/services/FeeManagement"
import FeeDetailModal from "./modal/DetailModal"
import FeeExternalModal from "./modal/FeeExternalModal"
import "./styles/index.scss"

const RevenueExpenditure = () => {
  const [loading, setLoading] = useState(false)
  const [openModalInsertExternal, setOpenModalInsertExternal] = useState(false)
  const [listData, setListData] = useState([])
  const [fromMoney, setFromMoney] = useState("")
  const [toMoney, setToMoney] = useState("")
  const [selectedRecord, setSelectedRecord] = useState(null)
  const [showDetailModal, setShowDetailModal] = useState(false)
  const [searchText, setSearchText] = useState("")
  const [fromDate, setFromDate] = useState(null)
  const [toDate, setToDate] = useState(dayjs().add(1, "day"))
  const { RangePicker } = DatePicker
  const [feeType, setFeeType] = useState(1)
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
  })

  const { listSystemKey } = useSelector(state => state.appGlobal)

  const feeTypeList = useMemo(
    () => getListComboByKey(SYSTEM_KEY.FEE_TYPE, listSystemKey) || [],
    [listSystemKey],
  )

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      key: "index",
      width: 70,
      align: "center",
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
    },
    {
      title: "Mã Số",
      dataIndex: "FeeCode",
      key: "FeeCode",
      align: "center",
      width: 180,
    },
    {
      title: "Mô tả",
      dataIndex: "Note",
      key: "Note",
      align: "center",
    },
    {
      title: (
        <div>
          <MainTableData>Nguồn/Đích</MainTableData>
          <SubTableData style={{ color: "white" }}>Phạm vi</SubTableData>
        </div>
      ),
      align: "center",
      render: (_, record) => {
        let name = "-"

        if (record?.TransactionType === 1) {
          // Nội bộ
          name =
            record?.FeeType === 2
              ? record?.ReceiverName
              : record?.FeeType === 1
              ? record?.SenderName
              : "-"
        } else {
          // Bên ngoài
          name = record?.EntityName || "-"
        }

        return (
          <div>
            <MainTableData className="max-line1">{name || "-"}</MainTableData>
            <SubTableData className="fs-13">
              {record?.TransactionType === 1 ? "Nội bộ" : "Bên ngoài"}
            </SubTableData>
          </div>
        )
      },
    },
    {
      title: "Ngày Tạo",
      dataIndex: "CreateDate",
      key: "CreateDate",
      align: "center",
      width: 160,
      render: value => {
        // Kiểm tra giá trị đặc biệt "0001-01-01..." => bỏ qua hoặc thay thế
        if (!value || value.startsWith("0001-01-01")) {
          return <span style={{ color: "#999" }}>--</span>
        }
        // Định dạng ngày tháng
        return dayjs(value).format("DD/MM/YYYY")
      },
    },
    {
      title: "Thu / Chi (VNĐ)",
      dataIndex: "Amount",
      key: "Amount",
      align: "right",
      width: 170,
      render: (val,) => {
        let color = "green"
        let sign = "+"

        if (feeType === 2) {
          // Chi
          color = "red"
          sign = "-"
        } else if (feeType === 1) {
          // Thu hoặc Donate
          color = "green"
          sign = "+"
        }

        return (
          <div
            style={{
              color: color,
              fontWeight: "600",
              fontSize: "16px",
            }}
          >
            {sign}
            {formatCurrency(val)} đ
          </div>
        )
      },
    },
  ]

  const handleViewDetail = record => {
    setSelectedRecord(record)
    setShowDetailModal(true)
  }

  const formatCurrency = value => {
    if (typeof value !== "number") value = Number(value)
    return value.toLocaleString("vi-VN")
  }

  const handleSearch = value => {
    setSearchText(value)
    setPagination(prev => ({ ...prev, CurrentPage: 1 }))
  }

  const getList = async () => {
    try {
      setLoading(true)

      const filters = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        TextSearch: searchText,
        FeeStatus: 2,
        FeeType: feeType,
      }

      if (fromDate) filters.StartDate = fromDate.format("YYYY/MM/DD")
      if (toDate) filters.EndDate = toDate.add(1, "day").format("YYYY/MM/DD")
      if (fromMoney) filters.FromMoney = fromMoney
      if (toMoney) filters.ToMoney = toMoney

      const res = await FeeManagement.getFeeTransactionList(filters)

      if (res?.isError) return
      setListData(res?.Object)
    } catch (error) {
      console.log("error>>getList:", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getList()
  }, [pagination, searchText, fromDate, toDate, fromMoney, toMoney])

  return (
    <SpinCustom spinning={loading}>
      <Row gutter={[16, 16]} align="middle" style={{ marginBottom: 16 }}>
        <Col span={24}>
          <TitleCustom className={"d-flex-sb"}>
            <span>Danh sách thu chi </span>
            <div className="d-flex-end">
              <ButtonCustom
                icon={<SvgIcon name="uploadVBMIcon" />}
                onClick={() => {}}
                className="mr-8"
              >
                Xuất Excel
              </ButtonCustom>

              <ButtonCustom
                type="primary"
                icon={<SvgIcon name="add-primary" />}
                className="btn-hover-shadow"
                onClick={() => setOpenModalInsertExternal(true)}
              >
                Tạo thu/chi bên ngoài
              </ButtonCustom>
            </div>
          </TitleCustom>
        </Col>
        <Col span={6}>
          <InputCustom
            type="search"
            placeholder="Tìm kiếm theo hiệp hội "
            allowClear
            onSearch={handleSearch}
          />
        </Col>

        <Col span={8}>
          <RangePicker
            style={{ width: "100%" }}
            format="DD/MM/YYYY"
            placeholder={["Từ ngày", "Đến ngày"]}
            value={fromDate && toDate ? [fromDate, toDate] : []}
            onChange={dates => {
              if (dates) {
                setFromDate(dates[0])
                setToDate(dates[1])
              } else {
                setFromDate(null)
                setToDate(null)
              }
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        <Col span={4}>
          <div style={{ display: "flex", flexDirection: "column" }}>
            <SelectCustom
              placeholder="Kiểu giao dịch"
              value={feeType}
              onChange={value => {
                setFeeType(value)
                setPagination(prev => ({ ...prev, CurrentPage: 1 }))
              }}
              className="w-full"
            >
              {feeTypeList.map(item => (
                <SelectCustom.Option key={item.CodeKey} value={item.CodeValue}>
                  {item.Description}
                </SelectCustom.Option>
              ))}
            </SelectCustom>
          </div>
        </Col>

        {/* Lọc theo số tiền từ */}
        <Col span={3}>
          <InputNumber
            style={{ width: "100%" }}
            placeholder="≥ Số tiền"
            min={0}
            value={fromMoney}
            onChange={value => {
              setFromMoney(value)
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        {/* Lọc theo số tiền đến */}
        <Col span={3}>
          <InputNumber
            style={{ width: "100%" }}
            placeholder="≤ Số tiền"
            min={0}
            value={toMoney}
            onChange={value => {
              setToMoney(value)
              setPagination(prev => ({ ...prev, CurrentPage: 1 }))
            }}
          />
        </Col>

        <Col span={24}>
          <TableCustom
            sticky={{ offsetHeader: -12 }}
            columns={columns}
            dataSource={listData?.ListData}
            loading={loading}
            textEmpty="Không có dữ liệu"
            scroll={{ x: "800px" }}
            pagination={{
              hideOnSinglePage: listData?.TotalCount <= hideOnSinglePage,
              current: pagination?.CurrentPage,
              pageSize: pagination?.PageSize,
              responsive: true,
              total: listData?.TotalCount,
              locale: { items_per_page: "" },
              showSizeChanger: listData?.TotalCount > 10,
              onChange: (CurrentPage, PageSize) => {
                setPagination(pre => ({
                  ...pre,
                  CurrentPage,
                  PageSize,
                }))
              },
            }}
            rowClassName={() => {
              if (feeType === 1) return "row__collect"

              if (feeType === 2) return "row__spent"

              return ""
            }}
            rowKey="FeeTransactionID"
            onRow={record => ({
              onClick: () => handleViewDetail(record),
            })}
          />
        </Col>
      </Row>
      {openModalInsertExternal && (
        <FeeExternalModal
          visible={openModalInsertExternal}
          onOk={() => {
            setOpenModalInsertExternal(false)
          }}
          onCancel={() => {
            setOpenModalInsertExternal(false)
          }}
          onSuccess={getList}
        />
      )}
      <FeeDetailModal
        open={{ isOpen: showDetailModal, record: selectedRecord }}
        onClose={() => setShowDetailModal(false)}
      />
    </SpinCustom>
  )
}

export default RevenueExpenditure
