import { Descriptions, Tag } from "antd";
import PropTypes from "prop-types";
import CustomModal from "src/components/Modal/CustomModal";
import {
  InfoCircleOutlined,
  NumberOutlined,
  DollarCircleOutlined,
  CalendarOutlined,
  ApartmentOutlined,
  FileTextOutlined,
  CheckCircleOutlined,
  SwapOutlined,
} from "@ant-design/icons";

const FeeDetailModal = ({ open, onClose }) => {
  const { isOpen, record } = open || {};
  if (!isOpen || !record) return null;

  const {
    FeeCode,
    TransactionType,
    CreateDate,
    Amount,
    Note,
    FeeType,
    SenderName,
    ReceiverName,
    EntityName,
  } = record;

  const formattedDate = CreateDate
    ? new Date(CreateDate).toLocaleDateString("vi-VN", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
    })
    : "(Không rõ)";

  const renderTypeTag = () => (
    <Tag color={TransactionType === 1 ? "blue" : "green"}>
      {TransactionType === 1 ? "Nội bộ" : "Bên ngoài"}
    </Tag>
  );

  const renderFeeTag = () => (
    <Tag color={FeeType === 1 ? "success" : "error"}>
      {FeeType === 1 ? "Giao dịch thu" : "Giao dịch chi"}
    </Tag>
  );

  return (
    <CustomModal
      open={isOpen}
      onCancel={onClose}
      footer={null}
      title="Chi tiết khoản phí"
      width={650}
    >
      <Descriptions
        bordered
        column={1}
        labelStyle={{ fontWeight: "bold", background: "#f0f2f5" }}
        contentStyle={{ background: "#ffffff" }}
      >
        <Descriptions.Item label={<><FileTextOutlined /> Ghi chú</>}>
          {Note || "(Không có ghi chú)"}
        </Descriptions.Item>

        <Descriptions.Item label={<><NumberOutlined /> Mã giao dịch</>}>
          {FeeCode || "(Không có)"}
        </Descriptions.Item>

        <Descriptions.Item label={<><ApartmentOutlined /> Phạm vi</>}>
          {renderTypeTag()}
        </Descriptions.Item>

        <Descriptions.Item label={<><SwapOutlined /> Loại giao dịch</>}>
          {renderFeeTag()}
        </Descriptions.Item>

        <Descriptions.Item label={<><DollarCircleOutlined /> Số tiền</>}>
          <span style={{ fontSize: "16px", fontWeight: "bold", color: "#cf1322" }}>
            {Amount ? Amount.toLocaleString("vi-VN") : "0"} ₫
          </span>
        </Descriptions.Item>

        <Descriptions.Item label={<><CalendarOutlined /> Ngày giao dịch</>}>
          {formattedDate}
        </Descriptions.Item>

        <Descriptions.Item label={<><InfoCircleOutlined /> Đơn vị Gửi</>}>
          {TransactionType !== 1
            ? (FeeType === 2 ? (SenderName || "(Không rõ)") : (EntityName || "(Không rõ)"))
            : (SenderName || "(Không rõ)")}
        </Descriptions.Item>

        <Descriptions.Item label={<><InfoCircleOutlined /> Đơn vị nhận</>}>
          {TransactionType !== 1
            ? (FeeType === 2 ? (EntityName || "(Không rõ)") : (ReceiverName || "(Không rõ)"))
            : (ReceiverName || "(Không rõ)")}
        </Descriptions.Item>

        <Descriptions.Item label={<><CheckCircleOutlined /> Trạng thái</>}>
          <Tag color="success" style={{ fontWeight: "bold" }}>
            Đã xác nhận
          </Tag>
        </Descriptions.Item>
      </Descriptions>
    </CustomModal>
  );
};

FeeDetailModal.propTypes = {
  open: PropTypes.shape({
    isOpen: PropTypes.bool.isRequired,
    record: PropTypes.object,
  }).isRequired,
  onClose: PropTypes.func.isRequired,
};

export default FeeDetailModal;
